class Solution:
    def maximumMedianSum(self, nums):
        n = len(nums)
        if n <= 12:
            best = [None]
            def rec(rem, acc):
                if not rem:
                    if best[0] is None or acc > best[0]:
                        best[0] = acc
                    return
                first = rem[0]
                rest = rem[1:]
                for a in range(len(rest)):
                    for b in range(a + 1, len(rest)):
                        trip = sorted([first, rest[a], rest[b]])
                        nxt = rest[:a] + rest[a+1:b] + rest[b+1:]
                        rec(nxt, acc + trip[1])
            rec(tuple(nums), 0)
            return best[0]
        arr = sorted(nums)
        return sum(arr[n - 2 - 2 * k] for k in range(n // 3))

