var maximumMedianSum = function(nums) {
    const arr = nums.slice().sort((a, b) => a - b);
    const n = arr.length;
    const m = n / 3;
    let total = 0;
    for (let k = 0; k < m; k++) total += arr[n - 2 - 2 * k];
    return total;
};
